============= 迪斯 订单异常-虚假订单 以及异常用户
-- 最近90天访问用户
with t1 as (
select
    silk_id,address_detail
    from test.test_client_user_location
    where date(updated_at) between date_sub(current_date(),interval 90 day) and date_sub(current_date(),interval 1 day)
)



-- 订单异常工单
select
    a.create_time `创建时间`,
    a.work_order_id `工单ID`,
    a.wore_order_type `一级工单类型`,
    a.cate2_type `二级工单类型`,
    a.cate3_type `三级工单类型`,
    a.status `工单状态`,
    a.content `工单内容`,
    a.order_id `订单ID`,
    a.store_id `店铺ID`,
    c.store_name `店铺名称`,
    a.user_id `用户ID`,
    b.user_real_name `用户真实姓名`,
    concat('身',b.user_id_num) `身份证ID`,
    b.inviter_user_id `团长ID`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num+b.tot_withdrawal_amt+b.withdrawal_candou_num as `累计蚕豆数`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num as `现有蚕豆数`,
    t1.address_detail `用户定位地址`
from
(select 
    create_time,
    work_order_id,
    wore_order_type, -- 工单类型(0:未知,1:消费者异常,2:商家异常,3:BD异常,4:客服异常,5:平台异常-前端把这个当成系统异常,6:第三方平台异常)
    cate2_type,
    cate3_type,
    status,
    content,
    concat('单',order_id) as order_id,
    store_id,
    user_id
from dwd.dwd_sr_callcenter_workorder
where cast(dt as string) between '2024-09-19' and '2024-11-19'
    and cate2_type=1 -- 订单异常
    and cate3_type=7 -- 1:多平台类型,10:评价折叠,7:虚假订单,60:用户反馈不符,23:全部退款
    -- and status=2 -- 0:待受理,1:受理中,2:已完结
) a
left join dim.dim_silkworm_user b on a.user_id=b.user_id
left join dim.dim_silkworm_store c on a.store_id=c.store_id
left join t1 on a.user_id=t1.silk_id
;




-- 异常用户
with t1 as (
select
    create_time,
    user_id
from dim.dim_silkworm_exception_user
where date(create_time)>='2024-07-01'
group by 1,2
),

-- 最近7天访问用户
t2 as (
select
    silk_id,address_detail
from test.test_client_user_location
where date(updated_at) between date_sub(current_date(),interval 90 day) and date_sub(current_date(),interval 1 day)
    and province in ('浙江省','四川省')
    and city in ('金华市','杭州市','成都市')
    and district in ('义乌市','西湖区','成华区')
)

select
    t1.user_id `用户ID`,
    b.user_real_name `用户真实姓名`,
    concat('身',b.user_id_num) `身份证ID`,
    b.inviter_user_id `团长ID`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num+b.tot_withdrawal_amt+b.withdrawal_candou_num as `累计蚕豆数`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num as `现有蚕豆数`,
    t2.address_detail `用户定位地址`
from t1
left join dim.dim_silkworm_user b on t1.user_id=b.user_id
inner join t2 on t1.user_id=t2.silk_id
;




-- 异常订单团长
-- 最近90天访问用户
with t1 as (
select
    silk_id,address_detail,province,city,district
    from test.test_client_user_location
    where date(updated_at) between date_sub(current_date(),interval 90 day) and date_sub(current_date(),interval 1 day)
),


-- 最新异常状态
t2 as (
select
    user_id,monitor_type,monitor_type_name
from
-- 异常状态
(select
    user_id,monitor_type,monitor_type_name,row_number() over(partition by user_id order by update_time desc) as rk
from dim.dim_silkworm_exception_user
where date(create_time)>='2022-01-01'
    and user_id in (492321903, 698697571, 737248854, 486955771, 924551575, 743375777,
     25735102, 148342900, 944152854, 14361018, 875622776, 249279700, 839414553, 168264556,
      593375774, 827373174, 798943652, 457281352, 235815774, 12921018, 913629574, 411827705,
       997293354, 995157178, 855547178, 764249573, 43778504, 586929572, 233537207, 517256779,
        927228091, 954489095, 198846017, 418597772, 784673170, 171777408, 68223106, 672979201,
     815654708, 393913178)
) a
where rk=1
)



select
    a.user_id `用户ID`,
    t2.monitor_type_name `状态`,
    a.user_real_name `用户真实姓名`,
    concat('身',a.user_id_num) `身份证ID`,
    a.inviter_user_id `团长ID`,
    (a.user_extra_point/100)+a.await_withdrawal_candou_num+a.tot_withdrawal_amt+a.withdrawal_candou_num as `累计蚕豆数`,
    (a.user_extra_point/100)+a.await_withdrawal_candou_num as `现有蚕豆数`,
    t1.province `省份名称`,
    t1.city `城市`,
    t1.district `区县`,
    t1.address_detail `用户定位地址`
from 
(select * from dim.dim_silkworm_user where user_id in (492321903, 698697571, 737248854, 486955771, 924551575, 743375777,
     25735102, 148342900, 944152854, 14361018, 875622776, 249279700, 839414553, 168264556,
      593375774, 827373174, 798943652, 457281352, 235815774, 12921018, 913629574, 411827705,
       997293354, 995157178, 855547178, 764249573, 43778504, 586929572, 233537207, 517256779,
        927228091, 954489095, 198846017, 418597772, 784673170, 171777408, 68223106, 672979201,
     815654708, 393913178)) a
left join t1 on a.user_id=t1.silk_id
left join t2 on a.user_id=t2.user_id
;





-- 2024年7月以来，拉黑异常用户
with t1 as (
select
    user_id,monitor_type,monitor_type_name
from
-- 异常状态
(select
    user_id,monitor_type,monitor_type_name,row_number() over(partition by user_id order by update_time desc) as rk
from dim.dim_silkworm_exception_user
where date(create_time)>='2024-07-01'
) a
where rk=1
    and monitor_type_name regexp '被拉黑'
),

-- 最近7天访问用户
t2 as (
select
    silk_id,address_detail,province,city,district
from test.test_client_user_location
where date(updated_at) between date_sub(current_date(),interval 90 day) and date_sub(current_date(),interval 1 day)
    and province in ('浙江省','四川省')
    and city in ('金华市','杭州市','成都市')
    and district in ('义乌市','西湖区','成华区')
)


select
    t1.user_id `用户ID`,
    b.user_real_name `用户真实姓名`,
    concat('身',b.user_id_num) `身份证ID`,
    b.inviter_user_id `团长ID`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num+b.tot_withdrawal_amt+b.withdrawal_candou_num as `累计蚕豆数`,
    (b.user_extra_point/100)+b.await_withdrawal_candou_num as `现有蚕豆数`,
    t2.province `省份名称`,
    t2.city `城市`,
    t2.district `区县`,
    t2.address_detail `用户定位地址`
from t1
left join dim.dim_silkworm_user b on t1.user_id=b.user_id
inner join t2 on t1.user_id=t2.silk_id
;



